import axios from "axios";

// Đảm bảo base URL và headers được cấu hình chính xác
const api = axios.create({
  baseURL: "http://localhost:5001", // Đảm bảo backend chạy ở cổng 5001
  headers: {
    "Content-Type": "application/json",
  }
});

// Lấy token từ localStorage và thêm vào headers khi cần thiết
export const getAuthHeaders = () => {
  const token = localStorage.getItem('userToken');  // Lấy token từ localStorage
  return {
    Authorization: `Bearer ${token}`,
  };
};

export default api;
